	sentinel := errors.New("boom")
	calls := 0
	err := Retry(3, time.Millisecond, func() error {
		calls++
		return sentinel
	})
	if calls != 3 {
		t.Errorf("calls=%d, want 3", calls)
	}
	if !errors.Is(err, sentinel) {
		t.Errorf("err=%v, want wraps sentinel", err)
	}
}
